<?php declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';$admin=vp3_require_admin_permission('releases.manage');if(vp3_method()==='POST'){vp3_verify_csrf();$sha=strtolower(vp3_input('artifact_sha256'));if(preg_match('/^[a-f0-9]{64}$/',$sha)){$stmt=vp3_db()->prepare("INSERT INTO product_releases(product_id,version,release_channel,commit_sha,artifact_path,artifact_sha256,release_notes,minimum_php_version,minimum_database_version,status,published_at,created_at,updated_at) VALUES(?,?,?,?,?,?,?,?,?,'published',NOW(),NOW(),NOW())");$stmt->execute([(int)vp3_input('product_id'),vp3_input('version'),vp3_input('release_channel','stable'),vp3_input('commit_sha'),vp3_input('artifact_path'),$sha,vp3_input('release_notes'),vp3_input('minimum_php_version','8.2'),vp3_input('minimum_database_version')]);vp3_audit('admin',(int)$admin['id'],'release.published','product_release',(string)vp3_db()->lastInsertId(),['version'=>vp3_input('version')]);vp3_flash('success','Release published.');}vp3_redirect('admin/releases.php');}$pageTitle='Product Releases';require VP3_ROOT.'/includes/admin-header.php';$products=vp3_db()->query("SELECT id,name FROM products WHERE status='active'")->fetchAll();$rows=vp3_db()->query('SELECT r.*,p.name product_name FROM product_releases r JOIN products p ON p.id=r.product_id ORDER BY r.published_at DESC,r.id DESC')->fetchAll();?><h1>Product releases</h1><div class="grid two"><form class="card" method="post"><?=vp3_csrf_field()?><h3>Publish approved release</h3><div class="field"><label>Product</label><select name="product_id"><?php foreach($products as $p):?><option value="<?=(int)$p['id']?>"><?=vp3_e($p['name'])?></option><?php endforeach;?></select></div><div class="field"><label>Version</label><input name="version" required></div><div class="field"><label>Channel</label><select name="release_channel"><option>stable</option><option>beta</option><option>development</option></select></div><div class="field"><label>Commit SHA</label><input name="commit_sha"></div><div class="field"><label>Internal artifact path</label><input name="artifact_path" required></div><div class="field"><label>Artifact SHA-256</label><input name="artifact_sha256" minlength="64" maxlength="64" required></div><div class="field"><label>Minimum PHP</label><input name="minimum_php_version" value="8.2"></div><div class="field"><label>Minimum database version</label><input name="minimum_database_version"></div><div class="field"><label>Release notes</label><textarea name="release_notes"></textarea></div><button class="button">Publish release</button></form><div class="table-wrap"><table class="table"><thead><tr><th>Product</th><th>Version</th><th>Channel</th><th>Status</th><th>Published</th></tr></thead><tbody><?php foreach($rows as $x):?><tr><td><?=vp3_e($x['product_name'])?></td><td><?=vp3_e($x['version'])?></td><td><?=vp3_e($x['release_channel'])?></td><td><span class="badge <?=vp3_e($x['status'])?>"><?=vp3_e($x['status'])?></span></td><td><?=vp3_e($x['published_at'])?></td></tr><?php endforeach;?></tbody></table></div></div><?php require VP3_ROOT.'/includes/admin-footer.php';?>